content.query:
let TimeChart = NTANetAnalytics
| where SubType == 'FlowLog' and FaSchemaVersion == '3'
| extend Timestamp = TimeGenerated
| extend Direction = case(tostring(FlowDirection) =~ "Inbound", "IN", tostring(FlowDirection) =~ "Outbound", "OUT", tostring(FlowDirection))
| extend Protocol = case(tostring(L4Protocol) =~ "T", "TCP", tostring(L4Protocol) =~ "U", "UDP", tostring(L4Protocol))
| where "{TileFilter}" != ""
| make-series Timeline = count() on Timestamp from {TimeRange:start} to {TimeRange:end} step {TimeRange:grain} by {TileFilter}
| project {TileFilter}, Timeline;
NTANetAnalytics
| where SubType == 'FlowLog' and FaSchemaVersion == '3'
| extend Direction = case(tostring(FlowDirection) =~ "Inbound", "IN", tostring(FlowDirection) =~ "Outbound", "OUT", tostring(FlowDirection))
| extend Protocol = case(tostring(L4Protocol) =~ "T", "TCP", tostring(L4Protocol) =~ "U", "UDP", tostring(L4Protocol))
| summarize ConnectionCount = count() by {TileFilter}
| join TimeChart on {TileFilter}
| extend FilterString = "{TileFilter}"
| project-rename Filter = {TileFilter}
